class Solution {
    public int lengthAfterTransformations(String s, int t, List<Integer> nums) {
        int MOD = (int) 1e9 + 7;
        int[] count = new int[26];
        for (char c : s.toCharArray()) {
            count[c - 'a']++;
        }

        int[][] transformMatrix = new int[26][26];
        for (int i = 0; i < 26; i++) {
            int nextCount = nums.get(i);
            int nextStart = (i + 1) % 26;
            for (int j = 0; j < nextCount; j++) {
                transformMatrix[i][(nextStart + j) % 26]++;
            }
        }

        int[][] powerMatrix = matrixPower(transformMatrix, t, MOD);
        int totalLength = 0;
        for (int i = 0; i < 26; i++) {
            int sum = 0;
            for (int j = 0; j < 26; j++) {
                sum = (sum + (int) ((long) powerMatrix[j][i] * count[j]) % MOD) % MOD;
            }
            totalLength = (totalLength + sum) % MOD;
        }

        return totalLength;
    }

    private int[][] matrixMultiply(int[][] a, int[][] b, int MOD) {
        int[][] result = new int[26][26];
        for (int i = 0; i < 26; i++) {
            for (int j = 0; j < 26; j++) {
                for (int k = 0; k < 26; k++) {
                    result[i][j] = (result[i][j] + (int) ((long) a[i][k] * b[k][j]) % MOD) % MOD;
                }
            }
        }
        return result;
    }

    private int[][] matrixPower(int[][] matrix, int n, int MOD) {
        int[][] result = new int[26][26];
        for (int i = 0; i < 26; i++) {
            result[i][i] = 1;
        }
        while (n > 0) {
            if (n % 2 == 1) {
                result = matrixMultiply(result, matrix, MOD);
            }
            matrix = matrixMultiply(matrix, matrix, MOD);
            n /= 2;
        }
        return result;
    }
}
